import React, { useState } from 'react';
import axios from 'axios';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';
import { Bar, Doughnut } from 'react-chartjs-2';
import './App.css'; // Import the new professional CSS

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend
);

const API_BASE = 'http://localhost:5000/api';
// Global variable for model availability (set this based on your backend response)
const model_available = false; 

// --- Core App Component ---
function App() {
  const [mode, setMode] = useState('individual');
  const [loading, setLoading] = useState(false);
  const [individualResults, setIndividualResults] = useState(null);
  const [batchResults, setBatchResults] = useState(null);

  const [customerData, setCustomerData] = useState({
    Tenure: 5.0,
    OrderCount: 5.0,
    CashbackAmount: 12000.0,
    DaySinceLastOrder: 7.0,
    HourSpendOnApp: 30.0,
    OrderAmountHikeFromlastYear: 15.0,
    CouponUsed: 1,
    NumberOfDeviceRegistered: 3,
    Complain: 0,
    SatisfactionScore: 3,
    WarehouseToHome: 10.0,
    NumberOfAddress: 4,
    CityTier: 1,
    PreferredLoginDevice: 'Mobile Phone',
    PreferredPaymentMode: 'Credit Card',
    PreferedOrderCat: 'Laptop & Accessory',
    Gender: 'Male',
    MaritalStatus: 'Married'
  });

  const [batchFile, setBatchFile] = useState(null);

  const handleInputChange = (field, value) => {
    setCustomerData(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleIndividualAnalysis = async () => {
    setLoading(true);
    setIndividualResults(null);
    try {
      const response = await axios.post(`${API_BASE}/analyze-single`, {
        customer_data: customerData
      });
      setIndividualResults(response.data);
    } catch (error) {
      console.error('Analysis error:', error);
      alert('Error analyzing customer data: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  const handleBatchAnalysis = async () => {
    if (!batchFile) {
      alert('Please select a file');
      return;
    }

    setLoading(true);
    setBatchResults(null);
    const formData = new FormData();
    formData.append('file', batchFile);

    try {
      const response = await axios.post(`${API_BASE}/analyze-batch`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });
      setBatchResults(response.data);
    } catch (error) {
      console.error('Batch analysis error:', error);
      alert('Error analyzing batch data: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  return (
    <div className="executive-dashboard-app">
      <Header />

      {!model_available && (
        <div className="info-banner">
          <strong>Model Status</strong>: Using <strong>simulated predictions and feature importances</strong> for demo. To enable real predictions: 1. Install required packages: <code>pip install xgboost catboost</code> 2. Place 'best_ensemble_churn_model.pkl' and 'feature_names.pkl' into the <code>Artifacts/</code> folder.
        </div>
      )}

      <div className="main-layout-container">
        <Sidebar mode={mode} setMode={setMode} model_available={model_available} />

        <div className="main-content-panel">
          {mode === 'individual' ? (
            <IndividualAnalysis 
              customerData={customerData}
              onInputChange={handleInputChange}
              onAnalyze={handleIndividualAnalysis}
              loading={loading}
              results={individualResults}
            />
          ) : (
            <BatchAnalysis 
              onFileChange={(e) => setBatchFile(e.target.files[0])}
              onAnalyze={handleBatchAnalysis}
              loading={loading}
              results={batchResults}
            />
          )}
        </div>
      </div>
    </div>
  );
}

// --- Header Component ---
const Header = () => (
  <div className="header-card">
    <div className="header-content">
      <div className="header-left">
        <div className="logo-container">
          <img src="https://img.icons8.com/fluency/48/000000/customer-insight.png" width="38" alt="logo" />
        </div>
        <div className="header-text">
          <div className="header-title">🚀 Executive Churn Intelligence Platform</div>
          <div className="header-subtitle">Unified predictive insights — action-first, financialized, and presentation-ready</div>
        </div>
      </div>
      <div className="header-right">
        <div className="timestamp">
          📅 Last updated: <strong>{new Date().toLocaleString()}</strong>
        </div>
      </div>
    </div>
  </div>
);

// --- Sidebar Component ---
const Sidebar = ({ mode, setMode, model_available }) => (
  <div className="sidebar">
    <div className="sidebar-section">
      <div className="sidebar-header">
        <h2>🎯 Analysis Mode</h2>
        <p>Choose your analysis approach</p>
      </div>

      <div className="radio-group">
        <label className={`radio-label ${mode === 'individual' ? 'active' : ''}`}>
          <input
            type="radio"
            name="analysis-mode"
            value="individual"
            checked={mode === 'individual'}
            onChange={() => setMode('individual')}
          />
          Individual Profile Analysis
        </label>
        <label className={`radio-label ${mode === 'batch' ? 'active' : ''}`}>
          <input
            type="radio"
            name="analysis-mode"
            value="batch"
            checked={mode === 'batch'}
            onChange={() => setMode('batch')}
          />
          Batch File Upload
        </label>
      </div>
    </div>

    <div className="sidebar-section">
      <h3>⚡ Quick Actions</h3>
      <button className="sidebar-button">
        📸 Export Dashboard PDF
      </button>
      <button className="sidebar-button">
        📚 View Documentation
      </button>
    </div>

    {!model_available && (
      <div className="sidebar-section">
        <h3>ℹ️ Model Status</h3>
        <div className="warning-banner">
          Using simulated predictions for demo.
        </div>
      </div>
    )}
  </div>
);

// --- Individual Analysis Component ---
const IndividualAnalysis = ({ customerData, onInputChange, onAnalyze, loading, results }) => {
  const [activeTab, setActiveTab] = useState('core');

  const renderInputField = (label, field, type = 'number', options = null) => {
    if (type === 'select') {
      return (
        <div className="input-group">
          <label>{label}</label>
          <select 
            value={customerData[field]} 
            onChange={(e) => onInputChange(field, e.target.value)}
          >
            {options.map(option => (
              <option key={option} value={option}>{option}</option>
            ))}
          </select>
        </div>
      );
    }

    if (type === 'toggle') {
      return (
        <div className="input-group">
          <label>{label}</label>
          <div className="toggle-group">
            <button 
              type="button"
              className={`toggle-btn ${customerData[field] === 1 ? 'active' : ''}`}
              onClick={() => onInputChange(field, 1)}
            >
              Yes
            </button>
            <button 
              type="button"
              className={`toggle-btn ${customerData[field] === 0 ? 'active' : ''}`}
              onClick={() => onInputChange(field, 0)}
            >
              No
            </button>
          </div>
        </div>
      );
    }

    return (
      <div className="input-group">
        <label>{label}</label>
        <input 
          type={type}
          value={customerData[field]}
          onChange={(e) => onInputChange(field, parseFloat(e.target.value) || e.target.value)}
          step={type === 'number' ? 'any' : undefined}
        />
      </div>
    );
  };

  return (
    <div className="individual-analysis">
      <div className="section-header">
        <h2>👤 Customer Profile Data Input</h2>
      </div>

      {/* Tabs for Input */}
      <div className="tabs-container">
        <div className="tabs">
          <button className={`tab ${activeTab === 'core' ? 'active' : ''}`} onClick={() => setActiveTab('core')}>💰 Core Metrics</button>
          <button className={`tab ${activeTab === 'service' ? 'active' : ''}`} onClick={() => setActiveTab('service')}>🛠️ Service & Logistics</button>
          <button className={`tab ${activeTab === 'demographic' ? 'active' : ''}`} onClick={() => setActiveTab('demographic')}>🧑‍ Demographic Data</button>
        </div>

        <div className="tab-content">
          {activeTab === 'core' && (
            <div className="tab-panel">
              <div className="input-columns">
                <div className="input-column">
                  {renderInputField("1. Customer Lifetime (Months)", "Tenure")}
                  {renderInputField("2. Total Orders", "OrderCount")}
                  {renderInputField("3. Total Cashback Earned (₹)", "CashbackAmount")}
                  {renderInputField("4. Days Since Last Order", "DaySinceLastOrder")}
                </div>
                <div className="input-column">
                  {renderInputField("5. App Time (Hours/month)", "HourSpendOnApp")}
                  {renderInputField("6. Perceived Price Increase (%)", "OrderAmountHikeFromlastYear")}
                  {renderInputField("7. Coupons Used", "CouponUsed")}
                  {renderInputField("8. Devices Registered", "NumberOfDeviceRegistered")}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'service' && (
            <div className="tab-panel">
              <div className="input-columns">
                <div className="input-column">
                  {renderInputField("9. Has a Formal Complaint?", "Complain", "toggle")}
                  {renderInputField("10. Satisfaction Score (1-5)", "SatisfactionScore")}
                  {renderInputField("11. Warehouse Distance (km)", "WarehouseToHome")}
                  {renderInputField("12. Delivery Addresses", "NumberOfAddress")}
                </div>
                <div className="input-column">
                  {renderInputField("15. City Tier", "CityTier")}
                  {renderInputField("16. Login Device", "PreferredLoginDevice", "select", ['Mobile Phone', 'Computer'])}
                  {renderInputField("17. Payment Mode", "PreferredPaymentMode", "select", ['Debit Card', 'Credit Card', 'UPI', 'E wallet', 'Cash on Delivery'])}
                  {renderInputField("18. Order Category", "PreferedOrderCat", "select", ['Laptop & Accessory', 'Mobile Phone', 'Fashion', 'Grocery', 'Books & Stationery', 'Footwear', 'Sports Equipment', 'Others'])}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'demographic' && (
            <div className="tab-panel">
              <div className="input-columns">
                <div className="input-column">
                  {renderInputField("13. Gender", "Gender", "select", ['Female', 'Male', 'Other'])}
                </div>
                <div className="input-column">
                  {renderInputField("14. Marital Status", "MaritalStatus", "select", ['Single', 'Married', 'Divorced', 'Other'])}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      <button 
        className="analyze-button primary"
        onClick={onAnalyze}
        disabled={loading}
      >
        {loading ? 'Analyzing...' : '✨ Analyze Customer Risk Now'}
      </button>

      {/* Results */}
      {results && (
        <ResultsDisplay 
          results={results} 
          customerData={customerData}
        />
      )}
    </div>
  );
};

// --- Batch Analysis Component ---
const BatchAnalysis = ({ onFileChange, onAnalyze, loading, results }) => {
  return (
    <div className="batch-analysis">
      <div className="section-header">
        <h2>Bulk Customer Risk Assessment</h2>
        <p>Upload a CSV file containing multiple customer profiles for mass risk segmentation.</p>
      </div>

      <div className="upload-section">
        <input 
          type="file" 
          accept=".csv"
          onChange={onFileChange}
          className="file-upload"
        />
        <button 
          className="analyze-button primary"
          onClick={onAnalyze}
          disabled={loading}
        >
          {loading ? 'Analyzing...' : '📊 Analyze Batch Data'}
        </button>
      </div>

      {results && (
        <BatchResultsDisplay 
          results={results}
        />
      )}
    </div>
  );
};

// --- Results Display Component (Individual) ---
const ResultsDisplay = ({ results, customerData }) => {
  const riskLevel = results.risk_level;
  const riskIcon = riskLevel === 'HIGH' ? '🚨' : riskLevel === 'MEDIUM' ? '⚠️' : '✅';

  return (
    <div className="results-section">
      <div className="section-header">
        <h2>✨ Churn Risk Analysis Report</h2>
      </div>

      {/* Risk Alert */}
      <div className={`risk-alert ${riskLevel.toLowerCase()}`}>
        {riskIcon} <strong>{riskLevel} RISK ({(results.probability * 100).toFixed(1)}%)</strong>: Primary risk factor identified as **{results.top_driver}**.
      </div>

      {/* Executive Summary */}
      <div className="executive-summary">
        <h3>EXECUTIVE SUMMARY</h3>
        <p>This customer is currently evaluated at a <strong>{(results.probability * 100).toFixed(2)}%</strong> churn probability and is categorized as {riskLevel.toLowerCase()} risk. We recommend proceeding directly to the action plan below.</p>
      </div>

      {/* KPI Cards */}
      <div className="kpi-grid">
        <KpiCard 
          title="Current Churn Risk" 
          value={`${(results.probability * 100).toFixed(1)}%`} 
          benchmark={50} 
          riskDirection={1} 
          unit="%"
        />
        <KpiCard 
          title="Customer Tenure" 
          value={`${results.profile['Tenure (Months)']}`} 
          benchmark={9} 
          riskDirection={-1} 
          unit="mo"
        />
        <KpiCard 
          title="Days Since Last Order" 
          value={`${results.profile['Days Since Last Order']}`} 
          benchmark={5} 
          riskDirection={1} 
          unit="d"
        />
        <KpiCard 
          title="Satisfaction Score" 
          value={`${results.profile['Satisfaction Score']}`} 
          benchmark={4} 
          riskDirection={-1} 
          unit="/5"
        />
      </div>

      {/* Business Impact */}
      <div className="business-impact">
        <h3>💼 Business Impact Analysis</h3>
        <div className="metric-grid">
          <MetricDisplay 
            value={`₹${results.business_impact.estimated_clv.toLocaleString()}`} 
            label="Estimated CLV" 
          />
          <MetricDisplay 
            value={`₹${results.business_impact.retention_budget.toLocaleString()}`} 
            label="Retention Budget" 
          />
          <MetricDisplay 
            value={`₹${results.business_impact.potential_revenue_loss.toLocaleString()}`} 
            label="Potential Loss" 
          />
          <MetricDisplay 
            value={`${results.business_impact.roi_retention.toFixed(1)}x`} 
            label="ROI Potential" 
          />
        </div>
      </div>

      {/* Risk Gauge */}
      <div className="gauge-section">
        <h3>📊 Predictive Risk Score</h3>
        <div className="gauge-container">
          <RiskGauge probability={results.probability} />
          <p style={{textAlign: 'center', fontStyle: 'italic', marginTop: '10px', color: '#94a3b8'}}>
            <strong>{(results.probability * 100).toFixed(2)}%</strong> Likelihood to Churn in the Next Quarter.
          </p>
        </div>
      </div>

      {/* Feature Contributions */}
      <div className="feature-contributions">
        <h3>💡 Key Churn Risk Factors (Feature Importance)</h3>
        <FeatureContributionChart contributions={results.feature_contributions} />
      </div>

      {/* Action Plan */}
      <ActionPlan 
        prediction={results.prediction}
        probability={results.probability}
        businessImpact={results.business_impact}
        topDriver={results.top_driver}
        inputData={customerData}
      />

      {/* Download Report */}
      <div className="download-section">
        <button className="download-button primary">
          📥 Download Comprehensive Customer Report (PDF)
        </button>
      </div>
    </div>
  );
};

// --- KPI Card Component ---
const KpiCard = ({ title, value, benchmark, riskDirection, unit }) => {
  let deltaText = "vs Target: N/A";
  let deltaColorClass = "kpi-delta-good";

  if (value !== 'N/A' && benchmark !== 0) {
    try {
      const valueNum = parseFloat(value);
      const benchmarkNum = parseFloat(benchmark);
      // Calculate delta based on absolute difference for display
      const deltaValue = valueNum - benchmarkNum;

      // Check if the value is 'worse' (higher riskDirection means higher is worse, lower means lower is worse)
      // riskDirection = 1 (higher is worse, e.g., Risk, Days Since Last Order)
      // riskDirection = -1 (lower is worse, e.g., Tenure, Satisfaction Score)
      const isWorse = (riskDirection === 1 && deltaValue > 0) || (riskDirection === -1 && deltaValue < 0);

      deltaText = `${Math.abs(deltaValue).toFixed(1)} ${unit} ${isWorse ? 'Worse' : 'Better'}`;
      deltaColorClass = isWorse ? "kpi-delta-bad" : "kpi-delta-good";

    } catch (error) {
      deltaText = "vs Target: N/A";
    }
  }

  return (
    <div className="kpi-card">
      <div className="kpi-title">{title}</div>
      <div className="kpi-value">{value}{unit}</div>
      <div className={deltaColorClass}>
        <span className='kpi-delta-icon'>
          {deltaColorClass.includes('bad') ? '▼' : '▲'}
        </span>
        {deltaText}
      </div>
    </div>
  );
};

// --- Metric Display Component ---
const MetricDisplay = ({ value, label }) => (
  <div className="metric">
    <div className="metric-value">{value}</div>
    <div className="metric-label">{label}</div>
  </div>
);


// --- Risk Gauge Component (Doughnut Chart) ---
const RiskGauge = ({ probability }) => {
  const pct = probability * 100;

  const data = {
    labels: ['Low', 'Moderate', 'High'],
    datasets: [
      {
        data: [30, 40, 30],
        backgroundColor: ['#34d399', '#f97316', '#ef4444'], // Green, Orange, Red
        borderWidth: 0,
        circumference: 180,
        rotation: 270,
      },
    ],
  };

  const options = {
    plugins: {
      legend: { display: false },
      tooltip: { enabled: false },
    },
    cutout: '80%', // Increased cutout for a cleaner look
  };

  const needle = {
    id: 'needle',
    afterDatasetsDraw(chart) {
      const { ctx } = chart;
      ctx.save();

      // Calculate angle: PI (180 deg) to 2*PI (360 deg) mapped to 0-100%
      const angle = Math.PI + (Math.PI * (pct / 100));
      const cx = chart.chartArea.left + (chart.chartArea.right - chart.chartArea.left) / 2;
      const cy = chart.chartArea.bottom; // Anchor point at the bottom center of the chart area
      const radius = chart.chartArea.bottom - chart.chartArea.top;

      // Draw needle
      ctx.translate(cx, cy);
      ctx.rotate(angle);
      ctx.beginPath();
      ctx.moveTo(0, -5);
      ctx.lineTo(radius * 0.9, 0); // Needle length
      ctx.lineTo(0, 5);
      ctx.closePath();
      ctx.fillStyle = '#f8fafc'; // White needle
      ctx.fill();

      // Draw needle center
      ctx.rotate(-angle);
      ctx.beginPath();
      ctx.arc(0, 0, 8, 0, 2 * Math.PI);
      ctx.fillStyle = '#7c3aed'; // Accent color for pin
      ctx.fill();

      ctx.restore();
    },
  };

  return (
    <div style={{ height: '200px', margin: '0 auto', maxWidth: '350px' }}>
      <Doughnut data={data} options={options} plugins={[needle]} />
      {/* Display Risk Level inside the gauge area (optional, requires custom plugin or overlay) */}
      <div style={{ position: 'relative', top: '-110px', textAlign: 'center' }}>
        <div style={{ fontSize: '36px', fontWeight: '700', color: '#f8fafc' }}>
          {pct.toFixed(0)}%
        </div>
        <div style={{ fontSize: '14px', color: '#94a3b8' }}>
          CHURN RISK
        </div>
      </div>
    </div>
  );
};

// --- Feature Contribution Chart (Horizontal Bar Chart) ---
const FeatureContributionChart = ({ contributions }) => {
  const topFeatures = contributions.slice(0, 10);

  const data = {
    labels: topFeatures.map(f => f.Feature.replace(/([A-Z])/g, ' $1').trim()), // Simple label formatting
    datasets: [
      {
        label: 'Contribution to Risk',
        data: topFeatures.map(f => f.Contribution),
        backgroundColor: topFeatures.map(f => f.Contribution > 0 ? '#ef4444' : '#34d399'), // Red for risk, Green for mitigating
        borderColor: topFeatures.map(f => f.Contribution > 0 ? '#dc2626' : '#059669'),
        borderWidth: 1,
      },
    ],
  };

  const options = {
    indexAxis: 'y',
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      title: { display: false },
      legend: { display: false },
      tooltip: { 
        callbacks: {
          label: (context) => `Contribution: ${context.parsed.x.toFixed(2)}`
        }
      },
    },
    scales: {
      x: {
        title: { display: true, text: 'Model Contribution Score', color: '#94a3b8' },
        grid: { color: '#334155' },
        ticks: { color: '#94a3b8' },
      },
      y: {
        grid: { color: '#334155' },
        ticks: { color: '#f8fafc', font: { size: 12 } },
      },
    },
  };

  return (
    <div style={{ height: '450px' }}>
      <Bar data={data} options={options} />
    </div>
  );
};

// --- Action Plan Component ---
const ActionPlan = ({ prediction, probability, businessImpact, topDriver, inputData }) => {
  const riskLevel = prediction === 1 ? "HIGH" : probability > 0.35 ? "MEDIUM" : "LOW";
  const riskColorClass = `action-plan-${riskLevel.toLowerCase()}-risk`;
  const primaryAction = riskLevel === 'HIGH' 
    ? `Address the **${topDriver}** issue with an immediate high-value retention offer.` 
    : `Leverage high satisfaction and **${topDriver}** to promote an upsell/referral program.`;

  return (
    <div className="action-plan-section">
      <div className="section-header">
        <h2>🎯 Customer Retention Action Plan</h2>
      </div>

      <div className={`action-plan-card ${riskColorClass}`}>
        <div className="action-plan-header">
          <div>
            <h3>**Primary Strategy: {riskLevel} PRIORITY**</h3>
            <p className="strategy-text">{primaryAction}</p>
          </div>
          <div className="risk-badge">
            <span className={`risk-level ${riskLevel.toLowerCase()}`}>{riskLevel}</span>
            <div>Churn Probability: **{(probability * 100).toFixed(1)}%**</div>
          </div>
        </div>

        {/* Quick Actions */}
        <div className="quick-actions">
          <h3>🚀 Next Steps</h3>
          <div className="action-buttons">
            <button className="action-button">📧 Send Personalized {riskLevel === 'HIGH' ? 'Urgent' : 'Loyalty'} Offer</button>
            <button className="action-button">📞 Schedule CX Outreach Call</button>
            <button className="action-button">⭐ Update CRM Flag</button>
          </div>
        </div>

        {/* Implementation Timeline */}
        <div className="implementation-timeline">
          <h3>📅 Recommended Roadmap</h3>
          <div className="roadmap-timeline">
            <div className={`roadmap-phase phase-0-${riskLevel.toLowerCase()}`}>
              <div className="roadmap-step-title">⚡ Phase 1: {riskLevel === 'HIGH' ? 'URGENT Stabilization' : 'Proactive Monitoring'}</div>
              <div className="roadmap-step-duration">Immediate (0-2 Days)</div>
              <div className="roadmap-step-description">{riskLevel === 'HIGH' ? 'Stop immediate churn threat. Executive visibility required. High-touch outreach.' : 'Confirm loyalty benefits. Send personalized "thank you" communication.'}</div>
            </div>
            {/* ... other phases can be added here based on riskLevel ... */}
          </div>
        </div>
      </div>
    </div>
  );
};

